"use client";

/* ════════════════════════════════════════════════════════════════════════
   Study subnav (spec §2.2) — the Study's own navigation, following the SAME
   interaction model as the room subnav (DeptSubnav): unpinned → a 24px
   trigger strip that hover-peeks; pin to keep it open; push layout; auto-opens
   briefly when you enter the Study. Shares the global useSubnavPin pref so the
   whole app has one subnav behavior. Navy material, Study content.
   Destinations: Conversations / Library / Record / Memory (Build is contextual).
   ════════════════════════════════════════════════════════════════════════ */

import Link from "next/link";
import { usePathname } from "next/navigation";
import { useEffect, useRef, useState } from "react";
import { useSubnavPin } from "@/lib/use-subnav-pin";
import "./StudySubnav.css";

const AUTO_OPEN_MS = 2500;

type Dest = { label: string; href: string; count: string; cls?: "urgent" | "accent"; icon: React.ReactNode; match?: (p: string) => boolean };

const DESTS: Dest[] = [
  {
    label: "Conversations", href: "/study", count: "290",
    match: (p) => p === "/study" || p.startsWith("/study/conversations") || p.startsWith("/study/build"),
    icon: <svg viewBox="0 0 24 24" fill="none" stroke="currentColor"><path d="M21 15a2 2 0 01-2 2H7l-4 4V5a2 2 0 012-2h14a2 2 0 012 2z" /></svg>,
  },
  {
    label: "Library", href: "/study/library", count: "147",
    icon: <svg viewBox="0 0 24 24" fill="none" stroke="currentColor"><polygon points="12 2 2 7 12 12 22 7 12 2" /><polyline points="2 17 12 22 22 17" /><polyline points="2 12 12 17 22 12" /></svg>,
  },
  {
    label: "Record", href: "/study/record", count: "3", cls: "urgent",
    icon: <svg viewBox="0 0 24 24" fill="none" stroke="currentColor"><polyline points="9 11 12 14 22 4" /><path d="M21 12v7a2 2 0 01-2 2H5a2 2 0 01-2-2V5a2 2 0 012-2h11" /></svg>,
  },
  {
    label: "Memory", href: "/study/memory", count: "1,247", cls: "accent",
    icon: <svg viewBox="0 0 24 24" fill="none" stroke="currentColor"><path d="M21 16V8a2 2 0 00-1-1.73l-7-4a2 2 0 00-2 0l-7 4A2 2 0 003 8v8a2 2 0 001 1.73l7 4a2 2 0 002 0l7-4A2 2 0 0021 16z" /><polyline points="3.27 6.96 12 12.01 20.73 6.96" /><line x1="12" y1="22.08" x2="12" y2="12" /></svg>,
  },
];

const THREADS = [
  { title: "Saturday Morning Brief", meta: "Pinned · 6:00 AM", pin: true },
  { title: "Premium positioning vs. volume", meta: "Pinned · 2d ago", pin: true },
  { title: "Where's the money actually leaking?", meta: "Today" },
  { title: "Why Mother's Day underperformed", meta: "Yesterday" },
  { title: "Kunming supplier relationship", meta: "Mon" },
  { title: "Should we revive the blog?", meta: "Wed" },
  { title: "Repeat-rate trajectory", meta: "Tue" },
];

export function StudySubnav() {
  const path = usePathname() ?? "/study";
  const [pinned, setPinned] = useSubnavPin();
  const [hover, setHover] = useState(false);
  const [autoOpen, setAutoOpen] = useState(false);
  const timer = useRef<ReturnType<typeof setTimeout> | null>(null);

  // Auto-open briefly when entering the Study (mirrors the rooms' auto-open
  // on dept change). The layout persists across surfaces, so this fires once.
  useEffect(() => {
    if (pinned) return;
    setAutoOpen(true);
    timer.current = setTimeout(() => setAutoOpen(false), AUTO_OPEN_MS);
    return () => { if (timer.current) clearTimeout(timer.current); };
  }, []); // eslint-disable-line react-hooks/exhaustive-deps

  const expanded = pinned || hover || autoOpen;
  const handleLeave = () => {
    setHover(false);
    if (autoOpen) { setAutoOpen(false); if (timer.current) clearTimeout(timer.current); }
  };

  return (
    <aside
      className="study-subnav"
      data-pin={pinned ? "pinned" : "unpinned"}
      data-expanded={expanded ? "true" : "false"}
      aria-label="Study navigation"
      onMouseEnter={() => setHover(true)}
      onMouseLeave={handleLeave}
    >
      <div className="study-subnav-strip" aria-hidden={expanded}>
        <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeLinecap="round" strokeLinejoin="round">
          <polyline points="9 6 15 12 9 18" />
        </svg>
      </div>

      <div className="study-subnav-panel" aria-hidden={!expanded}>
        <div className="sn-head">
          <span className="sn-title">Study</span>
          <button
            className={`study-subnav-anchor${pinned ? " pinned" : ""}`}
            onClick={() => setPinned(!pinned)}
            title={pinned ? "Unpin — collapse to a strip" : "Pin open"}
            aria-label={pinned ? "Unpin Study navigation" : "Pin Study navigation open"}
            type="button"
          >
            <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeLinecap="round" strokeLinejoin="round">
              <circle cx="12" cy="5" r="2" fill={pinned ? "currentColor" : "none"} />
              <line x1="12" y1="7" x2="12" y2="20" />
              <line x1="8" y1="11" x2="16" y2="11" />
              <path d="M5 14a7 7 0 0 0 7 6 7 7 0 0 0 7 -6" />
            </svg>
          </button>
        </div>

        <Link className="sn-new" href="/study">
          <svg viewBox="0 0 24 24" fill="none" stroke="currentColor"><line x1="12" y1="5" x2="12" y2="19" /><line x1="5" y1="12" x2="19" y2="12" /></svg>
          New conversation
        </Link>

        <div className="sn-content">
          {DESTS.map((d) => {
            const active = d.match ? d.match(path) : path.startsWith(d.href);
            return (
              <Link key={d.href} href={d.href} prefetch className={`sn-dest${active ? " active" : ""}`} aria-current={active ? "page" : undefined}>
                <span className="sn-ic">{d.icon}</span>
                <span className="sn-lab">{d.label}</span>
                <span className={`sn-ct${d.cls ? " " + d.cls : ""}`}>{d.count}</span>
              </Link>
            );
          })}

          <div className="sn-sec">Recent</div>
          <div className="sn-search">
            <svg viewBox="0 0 24 24" fill="none" stroke="currentColor"><circle cx="11" cy="11" r="7" /><line x1="21" y1="21" x2="16.65" y2="16.65" /></svg>
            <input placeholder="Search conversations…" />
          </div>
          <div className="sn-threads">
            {THREADS.map((t) => (
              <Link key={t.title} href="/study" className="sn-thread">
                <div className="sn-th-title">{t.title}</div>
                <div className="sn-th-meta">{t.pin && <span className="pin" />}{t.meta}</div>
              </Link>
            ))}
          </div>
          <Link className="sn-seeall" href="/study/conversations">See all conversations →</Link>
        </div>
      </div>
    </aside>
  );
}
